      required this.lifetimeValue,
      required this.openOpportunityCount,
      required this.deleted,
      this.territoryType,
      this.geofenceRadiusOverride,
      this.salesOrg,
      this.division,
      this.distributionChannel,
      this.customerGroup,
      this.priceGroup,
      this.enName,
      this.khName,
      required this.creditBalance,
