      this.taxNumber,
      required this.totalOrders,
      this.createdAt,
      required this.syncState});
  @override
  Map<String, Expression> toColumns(bool nullToAbsent) {
    final map = <String, Expression>{};
    map['id'] = Variable<String>(id);
    map['sap_customer_id'] = Variable<String>(sapCustomerId);
