      map['whatsapp'] = Variable<String>(whatsapp);
    }
    map['address'] = Variable<String>(address);
    map['province'] = Variable<String>(province);
    map['district'] = Variable<String>(district);
    map['territory'] = Variable<String>(territory);
    map['latitude'] = Variable<double>(latitude);
    map['longitude'] = Variable<double>(longitude);
    map['credit_limit'] = Variable<double>(creditLimit);
    map['status'] = Variable<String>(status);
    map['assigned_rep_id'] = Variable<String>(assignedRepId);
    map['assigned_rep_name'] = Variable<String>(assignedRepName);
    map['updated_at'] = Variable<DateTime>(updatedAt);
    if (!nullToAbsent || originLeadId != null) {
      map['origin_lead_id'] = Variable<String>(originLeadId);
    }
    map['products_purchased'] = Variable<String>(productsPurchased);
    if (!nullToAbsent || lastOrderDate != null) {
      map['last_order_date'] = Variable<DateTime>(lastOrderDate);
    }
    if (!nullToAbsent || lastVisitDate != null) {
      map['last_visit_date'] = Variable<DateTime>(lastVisitDate);
    }
    map['lifetime_value'] = Variable<double>(lifetimeValue);
    map['open_opportunity_count'] = Variable<int>(openOpportunityCount);
    map['deleted'] = Variable<bool>(deleted);
    if (!nullToAbsent || territoryType != null) {
      map['territory_type'] = Variable<String>(territoryType);
    }
    if (!nullToAbsent || geofenceRadiusOverride != null) {
      map['geofence_radius_override'] =
          Variable<double>(geofenceRadiusOverride);
    }
    if (!nullToAbsent || salesOrg != null) {
      map['sales_org'] = Variable<String>(salesOrg);
    }
    if (!nullToAbsent || division != null) {
      map['division'] = Variable<String>(division);
    }
    if (!nullToAbsent || distributionChannel != null) {
      map['distribution_channel'] = Variable<String>(distributionChannel);
    }
    if (!nullToAbsent || customerGroup != null) {
      map['customer_group'] = Variable<String>(customerGroup);
    }
    if (!nullToAbsent || priceGroup != null) {
      map['price_group'] = Variable<String>(priceGroup);
    }
    if (!nullToAbsent || enName != null) {
      map['en_name'] = Variable<String>(enName);
    }
    if (!nullToAbsent || khName != null) {
      map['kh_name'] = Variable<String>(khName);
    }
    map['credit_balance'] = Variable<double>(creditBalance);
    map['currency'] = Variable<String>(currency);
    if (!nullToAbsent || taxNumber != null) {
      map['tax_number'] = Variable<String>(taxNumber);
    }
    map['total_orders'] = Variable<int>(totalOrders);
    if (!nullToAbsent || createdAt != null) {
      map['created_at'] = Variable<DateTime>(createdAt);
    }
    map['sync_state'] = Variable<String>(syncState);
    return map;
  }

